import Chip from '@mui/material/Chip';

import { useNavigate } from 'react-router-dom';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import API_PATHS from 'lib/http/apiPaths';

export default function ParcelsPage() {
  const navigate = useNavigate();

  return (
    <CrudResourceModule
      title="Parcelas"
      path={API_PATHS.parcels}
      columns={[
        { key: 'codigo_parcela', label: 'Código Parcela' },
        { key: 'letra_lote', label: 'Lote' },
        { key: 'numero_lote', label: 'Número' },
        {
          key: 'estado',
          label: 'Estado',
          render: (row) => {
            const color = row.estado === 'ACTIVA' ? 'success' : row.estado === 'INACTIVA' ? 'default' : 'warning';
            return <Chip size="small" label={row.estado} color={color} />;
          }
        }
      ]}
      fields={[
        { name: 'codigo_parcela', label: 'Código de parcela (ej. N-19)', required: true },
        {
          name: 'estado',
          label: 'Estado',
          type: 'select',
          required: true,
          options: [
            { value: 'ACTIVA', label: 'Activa' },
            { value: 'INACTIVA', label: 'Inactiva' },
            { value: 'SUSPENDIDA', label: 'Suspendida' }
          ]
        },
        { name: 'referencia_direccion', label: 'Referencia dirección', fullWidth: true },
        { name: 'observaciones_generales', label: 'Observaciones generales', type: 'textarea', fullWidth: true }
      ]}
      defaultOrdering="codigo_parcela_key"
      extraFilters={[
        {
          key: 'estado',
          label: 'Estado',
          options: [
            { value: 'ACTIVA', label: 'Activa' },
            { value: 'INACTIVA', label: 'Inactiva' },
            { value: 'SUSPENDIDA', label: 'Suspendida' }
          ]
        }
      ]}
      searchPlaceholder="Buscar por código de parcela"
      onView={(row) => navigate(`/parcelas/${row.id}`)}
    />
  );
}
